#include <bits/stdc++.h>
using namespace std;
const int N=100005,mod=99999997;
int a[N],b[N],aa[N],bb[N],n,tr[N],ans;
map<int,int> mp;
bool cmp1(int x,int y)
{
	return a[x]<a[y];
}
bool cmp2(int x,int y)
{
	return b[x]<b[y];
}
void add(int x,int y)
{
	for(int i=x;i<=n;i+=(i&(-i)))
	{
		tr[i]+=y;
	}
}
int fun(int x) 
{
	int cnt=0;
	for(;x;x-=(x&(-x)))
	{
		cnt+=tr[x];
	}
	return cnt;
}
int main()
{
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
		aa[i]=i;
		bb[i]=i;
	}
	for(int i=1;i<=n;i++)
	{
		cin>>b[i];
	}
	sort(aa+1,aa+1+n,cmp1);
	sort(bb+1,bb+1+n,cmp2);
	for(int i=1;i<=n;i++)
	{
		a[aa[i]]=bb[i];
	}
	for(int i=n;i;i--)
	{
		ans=(ans+=fun(a[i]-1))%mod;
		add(a[i],1);
	}
	cout<<ans;
	return 0;
}
